export function getAppData() {
    try {
        const stored = localStorage.getItem('raeen_apps_data');
        if (stored) {
            const parsed = JSON.parse(stored);
            // Ensure both google and microsoft exist
            if (parsed.google && parsed.microsoft) return parsed;
        }
    } catch(e) {}
    return defaultAppData;
}

export function saveAppData(data) {
    localStorage.setItem('raeen_apps_data', JSON.stringify(data));
}

let currentProvider = 'google';

export function renderAppsMenu(provider = currentProvider) {
    currentProvider = provider;
    const grid = document.getElementById('apps-grid-dynamic');
    if (!grid) return;
    
    const data = getAppData();
    
    grid.innerHTML = data[provider].map((app, index) => {
        let domain = 'google.com';
        try { domain = new URL(app.url).hostname; } catch(e){}
        const fallback = `https://www.google.com/s2/favicons?domain=${domain}&sz=64`;
        return `
        <a href="${app.url}" target="_blank" class="app-item" draggable="true" data-index="${index}">
            <img src="${app.icon || fallback}" alt="${app.name}" onerror="this.onerror=null; this.src='${fallback}'">
            <span>${app.name}</span>
        </a>
        `;
    }).join('');
    
    const moreLink = document.getElementById('more-apps-link');
    if (moreLink) {
        moreLink.href = provider === 'google' ? 'https://about.google/products/' : 'https://www.microsoft.com/en-us/store/apps';
        moreLink.textContent = provider === 'google' ? 'More from Google' : 'More from Microsoft';
    }
    
    setupDragAndDrop(grid, provider);
}

function setupDragAndDrop(grid, provider) {
    let draggedIndex = null;

    const items = grid.querySelectorAll('.app-item');
    items.forEach(item => {
        item.addEventListener('dragstart', (e) => {
            draggedIndex = parseInt(item.dataset.index);
            e.dataTransfer.effectAllowed = 'move';
            item.classList.add('dragging');
        });

        item.addEventListener('dragend', () => {
            item.classList.remove('dragging');
            items.forEach(i => i.classList.remove('drag-over'));
        });

        item.addEventListener('dragover', (e) => {
            e.preventDefault(); // Necessary to allow dropping
            e.dataTransfer.dropEffect = 'move';
            item.classList.add('drag-over');
        });

        item.addEventListener('dragleave', () => {
            item.classList.remove('drag-over');
        });

        item.addEventListener('drop', (e) => {
            e.preventDefault();
            e.stopPropagation(); // prevent link navigation
            item.classList.remove('drag-over');
            
            const dropIndex = parseInt(item.dataset.index);
            if (draggedIndex !== null && draggedIndex !== dropIndex) {
                const data = getAppData();
                const list = data[provider];
                
                // Move the item in the array
                const [movedItem] = list.splice(draggedIndex, 1);
                list.splice(dropIndex, 0, movedItem);
                
                saveAppData(data);
                renderAppsMenu(provider);
            }
        });
        
        // Prevent default click if dragging? Not strictly needed if drop intercepts
    });
}
